@Configuration
@EnableAsync
public class AsyncConfig implements AsyncConfigurer {

    @Bean(name = "taskExecutor")
    public Executor taskExecutor() {
        ThreadPoolTaskExecutor executor = new ThreadPoolTaskExecutor();
        executor.setCorePoolSize(4);
        executor.setMaxPoolSize(8);
        executor.setQueueCapacity(100);
        executor.setThreadNamePrefix("Task-");
        executor.setRejectedExecutionHandler(new ThreadPoolExecutor.CallerRunsPolicy());
        executor.setWaitForTasksToCompleteOnShutdown(true);
        executor.setAwaitTerminationSeconds(30);
        executor.setTaskDecorator(new MdcTaskDecorator()); // propagates MDC
        executor.initialize();
        return executor;
    }

    @Bean(name = "emailExecutor")
    public Executor emailExecutor() {
        ThreadPoolTaskExecutor executor = new ThreadPoolTaskExecutor();
        executor.setCorePoolSize(2);
        executor.setMaxPoolSize(4);
        executor.setQueueCapacity(50);
        executor.setThreadNamePrefix("Email-");
        executor.setWaitForTasksToCompleteOnShutdown(true);
        executor.setAwaitTerminationSeconds(30);
        executor.initialize();
        return executor;
    }

    @Override
    public AsyncUncaughtExceptionHandler getAsyncUncaughtExceptionHandler() {
        return (ex, method, params) ->
            log.error("Uncaught async exception in {}", method.getName(), ex);
    }
}

@Service
@RequiredArgsConstructor
@Slf4j
public class NotificationService {

    private final EmailService emailService;

    @Async("emailExecutor")
    public CompletableFuture<Void> sendOrderConfirmation(Order order) {
        log.info("Sending confirmation for order {}", order.getId());
        try {
            emailService.send(
                order.getUser().getEmail(),
                "Order Confirmation",
                buildBody(order)
            );
            return CompletableFuture.completedFuture(null);
        } catch (Exception e) {
            log.error("Failed to send order confirmation for order {}", order.getId(), e);
            return CompletableFuture.failedFuture(e);
        }
    }
}

@Async  // no executor name — uses default, which changes between Boot versions
public void sendOrderConfirmation(Order order) { // void — exceptions are swallowed
    emailService.send(...);
}

@SpringBootTest
class NotificationServiceTest {

    @Autowired private NotificationService notificationService;

    @Test
    void sendOrderConfirmation_completesSuccessfully() {
        Order order = buildTestOrder();

        CompletableFuture<Void> future = notificationService.sendOrderConfirmation(order);

        await().atMost(5, SECONDS).until(future::isDone);
        assertThat(future).isCompletedWithoutException();
    }
}
